// E2E fixture-driven test for the cross-modal moonshine sieve. Builds a
// synthetic talking-head-style sequence (12 frames, ~2s at 6 fps) where
// visual luminance and audio amplitude have engineered disagreements at
// known positions: audio-only spikes at frames 6 and 8 (motion blur hint),
// a visual-only transient at frame 10 (lighting transient hint), and an
// aligned audio+visual burst across frames 2-4 (the talking-head normal
// mode). Validates that the sieve flags those positions correctly through
// per-frame sigma boosts and the aggregate Bule heartbeat counts.

import { describe, it, expect } from 'vitest';
import { crossModalSigmaScore } from '../src/cross-modal-moonshine';

describe('cross-modal moonshine e2e', () => {
  const visualSequence = new Float32Array([
    0.5, 0.5, 0.6, 0.7, 0.6, 0.5, 0.5, 0.5, 0.5, 0.5, 0.6, 0.5,
  ]);
  const audioSequence = new Float32Array([
    0.0, 0.0, 0.6, 0.7, 0.6, 0.0, 0.5, 0.0, 0.5, 0.0, 0.0, 0.0,
  ]);
  const baseSigma = 2.0;

  it('synthetic fixture runs without throwing and report has 12 entries', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    expect(report.sigmaPerFrame).toHaveLength(12);
    expect(report.agreementPerFrame).toHaveLength(12);
  });

  it('aligned frames (2-4) have low sigma adjustment', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    // Visual+audio change together at frames 2-4 (talking-head normal mode).
    // The moonshine impl normalizes each modality independently by its own
    // max, so absolute amplitude differences become relative. The honest
    // assertion is that aligned frames have HIGHER agreement (LOWER sigma)
    // than the engineered-disagreement frames at 6, 8, 10.
    const meanAgreed = (report.sigmaPerFrame[2] + report.sigmaPerFrame[3] + report.sigmaPerFrame[4]) / 3;
    const meanDisagreed = (report.sigmaPerFrame[6] + report.sigmaPerFrame[8] + report.sigmaPerFrame[10]) / 3;
    expect(meanAgreed).toBeLessThan(meanDisagreed);
  });

  it('audio-only frames (6, 8) boost sigma above baseSigma', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    // Audio active, visual still — motion blur hint.
    expect(report.sigmaPerFrame[6]).toBeGreaterThan(baseSigma * 1.05);
    expect(report.sigmaPerFrame[8]).toBeGreaterThan(baseSigma * 1.05);
  });

  it('visual-only frame (10) boosts sigma above baseSigma', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    // Visual change, audio silent — lighting transient hint.
    expect(report.sigmaPerFrame[10]).toBeGreaterThan(baseSigma * 1.05);
  });

  it('heartbeat classification catches opportunity and waste frames', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    // At least one audio-only frame caught (motion blur opportunity).
    expect(report.heartbeat.opportunity).toBeGreaterThanOrEqual(1);
    // At least one visual-only frame caught (lighting waste).
    expect(report.heartbeat.waste).toBeGreaterThanOrEqual(1);
    // Diversity covers the rest — should be positive too.
    expect(report.heartbeat.diversity).toBeGreaterThanOrEqual(1);
  });

  it('meanAgreement is moderate (engineered mix of agree + disagree)', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    expect(report.meanAgreement).toBeGreaterThan(0.3);
    expect(report.meanAgreement).toBeLessThan(0.9);
  });

  it('every sigmaPerFrame entry is bounded by [baseSigma, baseSigma * 1.5] for default strength', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    const lower = baseSigma;
    const upper = baseSigma * (1 + 0.5);
    for (let t = 0; t < report.sigmaPerFrame.length; t++) {
      // Allow tiny float epsilon on the lower bound.
      expect(report.sigmaPerFrame[t]).toBeGreaterThanOrEqual(lower - 1e-6);
      expect(report.sigmaPerFrame[t]).toBeLessThanOrEqual(upper + 1e-6);
    }
  });

  it('first frame stays at baseSigma (no delta possible from index 0)', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
    });
    expect(report.sigmaPerFrame[0]).toBe(baseSigma);
  });

  it('adjustmentStrength=0 disables the sieve (sigma is constant baseSigma)', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
      adjustmentStrength: 0,
    });
    for (let t = 0; t < report.sigmaPerFrame.length; t++) {
      expect(report.sigmaPerFrame[t]).toBeCloseTo(baseSigma, 6);
    }
  });

  it('adjustmentStrength=1.0 lets audio-only frames approach baseSigma * 2', () => {
    const report = crossModalSigmaScore({
      visual: visualSequence,
      audio: audioSequence,
      baseSigma,
      adjustmentStrength: 1.0,
    });
    // Frames 6 and 8 are audio-only — sigma should be near the 2x ceiling.
    // Allow a generous lower bound since exact value depends on normalized
    // delta arithmetic; "approaches" 2x means well past the default-strength cap.
    expect(report.sigmaPerFrame[6]).toBeGreaterThan(baseSigma * 1.5);
    expect(report.sigmaPerFrame[6]).toBeLessThanOrEqual(baseSigma * 2 + 1e-6);
    expect(report.sigmaPerFrame[8]).toBeGreaterThan(baseSigma * 1.5);
    expect(report.sigmaPerFrame[8]).toBeLessThanOrEqual(baseSigma * 2 + 1e-6);
  });
});
